import BpkText, { TEXT_STYLES } from '../../bpk-component-text';
import { cssModules } from '../../bpk-react-utils';

import BpkBubble from './BpkBubble';

import type { Meta } from '@storybook/react';

import STYLES from './BpkBubble.stories.module.scss';


const getClassNames = cssModules(STYLES);

const SimpleExample = () => (
  <div className={getClassNames('bpk-content')}>
    <span className={getClassNames('bpk-content__container')}>
      <BpkText textStyle={TEXT_STYLES.heading3} tagName="h3">
        Simple
      </BpkText>

      <span className={getClassNames('bpk-content__container__bubble-wrapper')}>
        <BpkBubble>
          New
        </BpkBubble>
      </span>
    </span>
  </div>
);

const WithLongLabelExample = () => (
  <div className={getClassNames('bpk-content')}>
    <span className={getClassNames('bpk-content__container')}>
      <BpkText textStyle={TEXT_STYLES.heading3} tagName="h3">
        With long label
      </BpkText>

      <span className={getClassNames('bpk-content__container__bubble-wrapper')}>
        <BpkBubble>
          Nouveau
        </BpkBubble>
      </span>
    </span>
  </div>
);

const VisualTestExample = () => (
  <div>
    <SimpleExample />
    <WithLongLabelExample />
  </div>
);

const meta = {
  title: 'bpk-component-bubble',
  component: BpkBubble,
} satisfies Meta;

export default meta;

export const Default = {
  render: () => <SimpleExample />,
};

export const LongLabel = {
  render: () => <WithLongLabelExample />,
};

export const VisualTest = {
  render: () => <VisualTestExample />,
};

export const VisualTestWithZoom = {
  render: () => <VisualTestExample />,
  args: {
    zoomEnabled: true,
  },
};
